import { openDB, DBSchema, IDBPDatabase } from 'idb';
import { Organization, Session, Agenda, Talk } from '@/types';

interface MinutesDB extends DBSchema {
  organizations: {
    key: string;
    value: Organization;
  };
  sessions: {
    key: string;
    value: Session;
  };
  agendas: {
    key: string;
    value: Agenda;
  };
  talks: {
    key: string;
    value: Talk;
  };
}

let dbPromise: Promise<IDBPDatabase<MinutesDB>> | null = null;

function getDB(): Promise<IDBPDatabase<MinutesDB>> {
  if (!dbPromise) {
    dbPromise = openDB<MinutesDB>('minutes-app', 1, {
      upgrade(db) {
        if (!db.objectStoreNames.contains('organizations')) {
          db.createObjectStore('organizations', { keyPath: 'id' });
        }
        if (!db.objectStoreNames.contains('sessions')) {
          db.createObjectStore('sessions', { keyPath: 'id' });
        }
        if (!db.objectStoreNames.contains('agendas')) {
          db.createObjectStore('agendas', { keyPath: 'id' });
        }
        if (!db.objectStoreNames.contains('talks')) {
          db.createObjectStore('talks', { keyPath: 'id' });
        }
      },
    });
  }
  return dbPromise;
}

// --- organizations ---

export async function getAllOrganizations(): Promise<Organization[]> {
  const db = await getDB();
  return db.getAll('organizations');
}

export async function getOrganizationById(id: string): Promise<Organization | undefined> {
  const db = await getDB();
  return db.get('organizations', id);
}

export async function saveOrganization(org: Organization): Promise<void> {
  const db = await getDB();
  await db.put('organizations', org);
}

export async function removeOrganization(id: string): Promise<void> {
  const db = await getDB();
  await db.delete('organizations', id);
}

